mapper.select:
SELECT r.id, r.reg_no AS regNo, r.patient_id AS patientId, p.name AS patientName, r.dept_id AS deptId, d.dept_name AS deptName, r.staff_id AS staffId, s.name AS staffName, r.reg_time AS regTime, r.reg_fee AS regFee, r.status FROM registration r LEFT JOIN patient p ON p.id = r.patient_id LEFT JOIN dept d ON d.id = r.dept_id LEFT JOIN staff s ON s.id = r.staff_id
AND r.patient_id = #{patientId} AND r.status = #{status}
ORDER BY r.reg_time DESC
